class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> contentMap;
        for (const auto& path : paths) {
            size_t spacePos = path.find(' ');
            string directory = path.substr(0, spacePos);
            string files = path.substr(spacePos + 1);
            size_t start = 0;
            while (start < files.size()) {
                size_t end = files.find(' ', start);
                if (end == string::npos) {
                    end = files.size();
                }
                string file = files.substr(start, end - start);
                size_t openParenPos = file.find('(');
                string fileName = file.substr(0, openParenPos);
                string content = file.substr(openParenPos + 1, file.size() - openParenPos - 2);
                contentMap[content].push_back(directory + '/' + fileName);
                start = end + 1;
            }
        }
        vector<vector<string>> result;
        for (const auto& pair : contentMap) {
            if (pair.second.size() > 1) {
                result.push_back(pair.second);
            }
        }
        return result;
    }
};

